import{_ as e,c as i,o as a,ag as r}from"./chunks/framework.QPV3Ar9-.js";const u=JSON.parse('{"title":"前言","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"guide/kubevirt/kubevirt_precheck.md","filePath":"guide/kubevirt/kubevirt_precheck.md","lastUpdated":1775354588000}'),l={name:"guide/kubevirt/kubevirt_precheck.md"};function s(d,t,n,c,o,p){return a(),i("div",null,t[0]||(t[0]=[r('<h1 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h1><p>以下为非自定义部分的介绍，自定义部分有自己对应的介绍，勿弄混了</p><p>欢迎给项目一个 <code>Star</code> 进行免费的支持--&gt;<a href="https://github.com/oneclickvirt/kubevirt" target="_blank" rel="noreferrer">https://github.com/oneclickvirt/kubevirt</a></p><h2 id="项目特点" tabindex="-1">项目特点 <a class="header-anchor" href="#项目特点" aria-label="Permalink to &quot;项目特点&quot;">​</a></h2><p>基于 KubeVirt 在 Kubernetes 集群（k3s）上一键部署并管理 KVM 虚拟机，通过批量或单独开设 KVM 虚拟机</p><ul><li>一键部署 k3s + KubeVirt 全套环境</li><li>基于 KubeVirt CRD，在 Kubernetes 环境中管理虚拟机</li><li>每台虚拟机自带独立 SSH 端口及端口映射</li><li>支持 IPv4/IPv6 自动分配与端口转发</li><li>支持批量开设，信息自动记录至日志文件</li><li>支持 X86_64 和 ARM64 架构</li><li>支持国内 CDN 镜像加速</li></ul><h2 id="支持的系统-宿主机" tabindex="-1">支持的系统（宿主机） <a class="header-anchor" href="#支持的系统-宿主机" aria-label="Permalink to &quot;支持的系统（宿主机）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>系统</th><th>amd64</th><th>arm64</th></tr></thead><tbody><tr><td>Debian 11</td><td>✓</td><td>✓</td></tr><tr><td>Debian 12</td><td>✓</td><td>✓</td></tr><tr><td>Ubuntu 20.04</td><td>✓</td><td>✓</td></tr><tr><td>Ubuntu 22.04</td><td>✓</td><td>✓</td></tr></tbody></table><h2 id="配置要求" tabindex="-1">配置要求 <a class="header-anchor" href="#配置要求" aria-label="Permalink to &quot;配置要求&quot;">​</a></h2><ul><li>宿主机节点需支持 KVM 硬件虚拟化（<code>/dev/kvm</code> 可用）</li><li>内核版本：≥ 4.15</li><li>架构：x86_64（amd64）或 ARM64</li><li>内存：至少 4GB 可用内存（含 k3s + KubeVirt 自身占用）</li><li>存储：至少 20GB 可用磁盘空间</li><li>系统：Debian 11+、Ubuntu 20.04+</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>使用本项目前请确保宿主机支持 KVM 虚拟化，可通过以下命令检测：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">egrep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;(vmx|svm)&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /proc/cpuinfo</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>输出大于 0 即支持 KVM 虚拟化。也可执行 <code>ls /dev/kvm</code> 确认设备文件存在。</p></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>本项目会自动部署 k3s，无需提前准备 Kubernetes 集群。</p></div><p>推荐在开设虚拟机前先增加部分 SWAP 虚拟内存，避免突发的内存占用导致宿主机卡死</p>',13)]))}const b=e(l,[["render",s]]);export{u as __pageData,b as default};
